     1→import { Inject, Injectable, Logger } from '@nestjs/common';
     2→import { Redis } from 'ioredis';
     3→import Keyv from 'keyv';
     4→import Redlock, { Lock } from 'redlock';
     5→
     6→import {
     7→	CACHE_READ_MANAGER,
     8→	CACHE_WRITE_MANAGER,
     9→	REDIS_READ_CLIENT,
    10→	REDIS_WRITE_CLIENT,
    11→} from '@modules/cache/cache.constant';
    12→import {
    13→	CacheError,
    14→	ConsistencyLevel,
    15→	Namespaces,
    16→} from '@modules/cache/types/cache.interface';
    17→
    18→export { ConsistencyLevel, CacheError } from '@modules/cache/types/cache.interface';
    19→
    20→@Injectable()
    21→export class CacheService {
    22→	private readonly logger = new Logger(CacheService.name);
    23→	private readonly redlock: Redlock;
    24→	private readonly redisWriteClient: Redis;
    25→	private readonly redisReadClient: Redis;
    26→	private readonly cacheWriteManager: Keyv;
    27→	private readonly cacheReadManager: Keyv;
    28→	private readonly recentWrites = new Map<string, number>();
    29→	private readonly CONSISTENCY_WINDOW_MS = 1000;
    30→	private isReadReplicaHealthy = true;
    31→
    32→	constructor(
    33→		@Inject(CACHE_WRITE_MANAGER) cacheWriteManager: Keyv,
    34→		@Inject(CACHE_READ_MANAGER) cacheReadManager: Keyv,
    35→		@Inject(REDIS_WRITE_CLIENT) redisWriteClient: Redis,
    36→		@Inject(REDIS_READ_CLIENT) redisReadClient: Redis,
    37→	) {
    38→		this.cacheWriteManager = cacheWriteManager;
    39→		this.cacheReadManager = cacheReadManager;
    40→		this.redisWriteClient = redisWriteClient;
    41→		this.redisReadClient = redisReadClient;
    42→		this.redlock = new Redlock([redisWriteClient], {
    43→			driftFactor: 0.01,
    44→			retryCount: 10,
    45→			retryDelay: 200,
    46→			retryJitter: 200,
    47→		});
    48→
    49→		this.setupHealthChecks();
    50→		this.startRecentWritesCleanup();
    51→	}
    52→
    53→	async get<T>({
    54→		namespace,
    55→		key,
    56→		consistencyLevel = ConsistencyLevel.EVENTUAL,
    57→	}: {
    58→		namespace: Namespaces;
    59→		key: string;
    60→		consistencyLevel?: ConsistencyLevel;
    61→	}): Promise<T | null> {
    62→		const namespacedKey = this.getNamespacedKey({ namespace, key });
    63→
    64→		const readFromMaster = this.shouldReadFromMaster({
    65→			namespace,
    66→			key: namespacedKey,
    67→			consistencyLevel,
    68→		});
    69→		const cacheManager = readFromMaster ? this.cacheWriteManager : this.cacheReadManager;
    70→		const source = readFromMaster ? 'master' : 'replica';
    71→
    72→		try {
    73→			const result = (await cacheManager.get(namespacedKey)) as T;
    74→
    75→			if (!result) {
    76→				this.logger.log('Cache miss', { namespace, key, consistencyLevel, source });
    77→				return null;
    78→			}
    79→
    80→			this.logger.log('Cache hit', { namespace, key });
    81→
    82→			return result;
    83→		} catch (error) {
    84→			const e = error as Error;
    85→			this.logger.error(`Error retrieving from cache: ${e.message}`, e.stack, { source });
    86→
    87→			if (!readFromMaster && this.isReadReplicaHealthy) {
    88→				this.logger.warn('Read replica failed, falling back to master', {
    89→					namespace,
    90→					key,
    91→				});
    92→				this.isReadReplicaHealthy = false;
    93→				return this.get({ namespace, key, consistencyLevel: ConsistencyLevel.STRONG });
    94→			}
    95→
    96→			throw this.createCacheError({ code: 'CONNECTION_FAILED', originalError: e });
    97→		}
    98→	}
