   100→	async set({
   101→		namespace,
   102→		key,
   103→		value,
   104→		ttl,
   105→	}: {
   106→		namespace: Namespaces;
   107→		key: string;
   108→		value: unknown;
   109→		ttl?: number;
   110→	}): Promise<void> {
   111→		const namespacedKey = this.getNamespacedKey({ namespace, key });
   112→
   113→		try {
   114→			await this.cacheWriteManager.set(namespacedKey, value, ttl);
   115→			this.trackRecentWrite({ key: namespacedKey });
   116→			this.logger.log('Cached value', { namespace, key, ttl });
   117→		} catch (error) {
   118→			const e = error as Error;
   119→			this.logger.error(`Error setting cache: ${e.message}`, e.stack);
   120→			throw this.createCacheError({ code: 'OPERATION_FAILED', originalError: e });
   121→		}
   122→	}
