   124→	async has({
   125→		namespace,
   126→		key,
   127→	}: {
   128→		namespace: Namespaces;
   129→		key: string;
   130→	}): Promise<boolean> {
   131→		this.logger.log('Checking cache key existence', { namespace, key });
   132→		const value = await this.get<unknown>({ namespace, key });
   133→		return value !== null;
   134→	}
   135→
   136→	async deleteOne({
   137→		namespace,
   138→		key,
   139→	}: {
   140→		namespace: Namespaces;
   141→		key: string;
   142→	}): Promise<boolean> {
   143→		try {
   144→			const namespacedKey = this.getNamespacedKey({ namespace, key });
   145→			await this.cacheWriteManager.delete(namespacedKey);
   146→			this.logger.log('Deleted cache key', { namespace, key });
   147→			return true;
   148→		} catch (error) {
   149→			const e = error as Error;
   150→			this.logger.error(`Error deleting from cache: ${e.message}`, e.stack);
   151→			return false;
   152→		}
   153→	}
   154→
   155→	async deleteAll({ namespace }: { namespace: Namespaces }): Promise<boolean> {
   156→		try {
   157→			await this.cacheWriteManager.clear();
   158→
   159→			await new Promise((resolve) => setTimeout(resolve, 100));
   160→
   161→			await this.cacheReadManager.clear();
   162→			this.recentWrites.clear();
   163→			this.logger.log('Cleared all cache', { namespace });
   164→			return true;
   165→		} catch (error) {
   166→			const e = error as Error;
   167→			this.logger.error(`Error clearing cache: ${e.message}`, e.stack);
   168→			return false;
   169→		}
   170→	}
