   172→	async incrementByOne({
   173→		namespace,
   174→		key,
   175→	}: {
   176→		namespace: Namespaces;
   177→		key: string;
   178→	}): Promise<void> {
   179→		try {
   180→			const namespacedKey = this.getNamespacedKey({ namespace, key });
   181→			await this.redisWriteClient.incr(namespacedKey);
   182→		} catch (error) {
   183→			const e = error as Error;
   184→			this.logger.error(`Error incrementing cache key: ${e.message}`, e.stack, {
   185→				namespace,
   186→				key,
   187→			});
   188→			throw error;
   189→		}
   190→	}
