   156→	async destroySessionsByCompanyId({
   157→		userId,
   158→		companyId,
   159→	}: {
   160→		userId: string;
   161→		companyId: string;
   162→	}): Promise<void> {
   163→		this.logger.log('Destroying sessions by company id', { userId, companyId });
   164→
   165→		const sessionSetKey = `sessions:${userId}`;
   166→		let sessionIds: string[] = [];
   167→
   168→		try {
   169→			sessionIds = await this.redisRead.smembers(sessionSetKey);
   170→		} catch {
   171→			this.logger.warn('Read replica failed for smembers, falling back to write client', {
   172→				userId,
   173→			});
   174→			sessionIds = await this.redisWrite.smembers(sessionSetKey);
