   218→	async rotateRefreshToken({
   219→		oldToken,
   220→		session,
   221→	}: {
   222→		oldToken: string;
   223→		session: ISession;
   224→	}): Promise<string> {
   225→		this.logger.log('Rotating refresh token', {
   226→			userId: session.user_id,
   227→			sessionId: session.session_id,
   228→		});
   229→
   230→		const tombstoneKey = `refresh_tombstone:${oldToken}`;
   231→		const oldRefreshKey = `refresh:${oldToken}`;
   232→		const newToken = randomUUID();
   233→		const newRefreshKey = `refresh:${newToken}`;
   234→
   235→		const payload: IRefreshToken = {
   236→			user_id: session.user_id,
   237→			session_id: session.session_id,
   238→		};
   239→
   240→		await this.redisWrite
   241→			.multi()
   242→			.del(oldRefreshKey)
   243→			.set(tombstoneKey, JSON.stringify(payload), 'EX', 3600)
   244→			.set(newRefreshKey, JSON.stringify(payload), 'EX', this.SESSION_TTL)
   245→			.exec();
   246→
   247→		return newToken;
   248→	}
