import { FastifyThrottlerGuard } from '@modules/auth/guards/fastify-throttler.guard';

import type { FastifyReply, FastifyRequest } from 'fastify';

const mockRequest = { ip: '127.0.0.1' } as FastifyRequest;
const mockReply = { statusCode: 200 } as FastifyReply;

function createMockContext(): ExecutionContext {
	return {
		switchToHttp: jest.fn().mockReturnValue({
			getRequest: jest.fn().mockReturnValue(mockRequest),
			getResponse: jest.fn().mockReturnValue(mockReply),
		}),
		getHandler: jest.fn(),
		getClass: jest.fn(),
		getArgs: jest.fn(),
		getArgByIndex: jest.fn(),
		switchToRpc: jest.fn(),
		switchToWs: jest.fn(),
		getType: jest.fn(),
	} as unknown as ExecutionContext;
}

describe('FastifyThrottlerGuard', () => {
	let guard: FastifyThrottlerGuard;

	beforeEach(() => {
		guard = Object.create(FastifyThrottlerGuard.prototype);
	});

	it('should be defined', () => {
		expect(guard).toBeDefined();
	});

	describe('getRequestResponse', () => {
		it('should return req and res from HTTP context', () => {
			const context = createMockContext();

			const result = guard.getRequestResponse(context);

			expect(result.req).toBe(mockRequest);
			expect(result.res).toBe(mockReply);
		});
	});
});

